import{_ as a,o as t,c as o,a3 as n}from"./chunks/framework.CjquFG0V.js";const c=JSON.parse('{"title":"58. Pre Adoption Leave","description":"","frontmatter":{"title":"58. Pre Adoption Leave","eba":"Health Allied & Managers Admin 2021-2025","topics":["leave","parental-leave","preliminary"]},"headers":[],"relativePath":"ebas/has-managers-admin/common-terms/leave/58-pre-adoption-leave.md","filePath":"ebas/has-managers-admin/common-terms/leave/58-pre-adoption-leave.md"}'),r={name:"ebas/has-managers-admin/common-terms/leave/58-pre-adoption-leave.md"};function p(i,e,s,l,d,m){return t(),o("div",null,[...e[0]||(e[0]=[n('<h1 id="_58-pre-adoption-leave" tabindex="-1">58. Pre Adoption Leave <a class="header-anchor" href="#_58-pre-adoption-leave" aria-label="Permalink to &quot;58. Pre Adoption Leave&quot;">​</a></h1><p><strong>58.1</strong> An Employee seeking to adopt a child is entitled to unpaid leave for the purpose of attending any compulsory interviews or examinations as are necessary as part of the adoption procedure.</p><p><strong>58.2</strong> The Employee and the Employer should agree on the length of the unpaid leave.</p><p><strong>58.3</strong> Where agreement cannot be reached the Employee is entitled to take up to two days unpaid leave.</p><p><strong>58.4</strong> Where paid leave is available to the Employee, the Employer may require the Employee to take such leave instead.</p><p>Plain language terms: adoption leave, adopting a child.</p>',6)])])}const v=a(r,[["render",p]]);export{c as __pageData,v as default};
